void test_CB_78_0000()
{
    if (skip_test_CB_78_0000)
    {
        TEST_SKIP("Skipping");
        return;
    }
    mmap.Reset();

    // Initial state

    WriteRegisterWord(RegisterType::PC, 0x5E8B);
    WriteRegisterWord(RegisterType::SP, 0xE373);
    WriteRegisterByte(RegisterType::A, 0xD0);
    WriteRegisterByte(RegisterType::B, 0x12);
    WriteRegisterByte(RegisterType::C, 0xBD);
    WriteRegisterByte(RegisterType::D, 0x47);
    WriteRegisterByte(RegisterType::E, 0xBD);
    WriteRegisterFlag(0xF0);
    WriteRegisterByte(RegisterType::H, 0x9D);
    WriteRegisterByte(RegisterType::L, 0x0E);
    mmap.EnableIME();
    WriteRegisterByte(RegisterType::IE, 0x01);
    WriteMemory(0x5E8C, 0x78);
    WriteMemory(0x5E8B, 0xCB);

    // Execute step
    {
        auto resultByte = mmap.ReadByte(mmap.ReadPC());
        TEST_ASSERT_(resultByte.IsSuccess(), "%s", resultByte.GetStatusDescription());
        auto ticks = ExecuteActiveDecoder(static_cast<const Byte&>(resultByte), mmap);
        TEST_ASSERT(ticks == GetInstructionTicks(static_cast<const Byte&>(resultByte), 0x00));

        // Execute additional step for prefix
        auto resultByte2 = mmap.ReadByte(mmap.ReadPC());
        TEST_ASSERT_(resultByte2.IsSuccess(), "%s", resultByte2.GetStatusDescription());
        auto ticks2 = ExecuteActiveDecoder(static_cast<const Byte&>(resultByte2), mmap);
        TEST_ASSERT(ticks2 == GetInstructionTicks(static_cast<const Byte&>(resultByte2), 0xCB));
        TEST_ASSERT(ticks + ticks2 == 8);
    }

    // Final state
            
    CheckRegisterByte(RegisterType::A, 0xD0);
    CheckRegisterByte(RegisterType::B, 0x12);
    CheckRegisterByte(RegisterType::C, 0xBD);
    CheckRegisterByte(RegisterType::D, 0x47);
    CheckRegisterByte(RegisterType::E, 0xBD);
    CheckRegisterFlag(0xB0);
    CheckRegisterByte(RegisterType::H, 0x9D);
    CheckRegisterByte(RegisterType::L, 0x0E);
    CheckRegisterWord(RegisterType::PC, 0x5E8D);
    CheckRegisterWord(RegisterType::SP, 0xE373);
    TEST_ASSERT(mmap.IMEEnabled());
    CheckMemory(0x5E8B, 0xCB);
    CheckMemory(0x5E8C, 0x78);
}

